24: import org.apache.kafka.streams.processor.api.Record;
25: 
26: import java.util.Objects;
27: 
28: class KStreamMap<KIn, VIn, KOut, VOut> implements ProcessorSupplier<KIn, VIn, KOut, VOut> {
29: 
30:     private final KeyValueMapper<? super KIn, ? super VIn, ? extends KeyValue<? extends KOut, ? extends VOut>> mapper;
31: 
32:     public KStreamMap(final KeyValueMapper<? super KIn, ? super VIn, ? extends KeyValue<? extends KOut, ? extends VOut>> mapper) {
33:         this.mapper = mapper;
34:     }
35: 
36:     @Override
37:     public Processor<KIn, VIn, KOut, VOut> get() {
38:         return new KStreamMapProcessor();
39:     }
40: 
41:     private class KStreamMapProcessor extends ContextualProcessor<KIn, VIn, KOut, VOut> {
42: 
43:         @Override
44:         public void process(final Record<KIn, VIn> record) {
45:             final KeyValue<? extends KOut, ? extends VOut> newPair =
46:                 mapper.apply(record.key(), record.value());
47:             Objects.requireNonNull(newPair, "The provided KeyValueMapper returned null which is not allowed.");
48:             context().forward(record.withKey(newPair.key).withValue(newPair.value));
49:         }
