125:     private class KTableMapValuesProcessor implements Processor<KIn, Change<VIn>, KIn, Change<VOut>> {
126:         private ProcessorContext<KIn, Change<VOut>> context;
127:         private KeyValueStoreWrapper<KIn, VOut> store;
