132:             this.context = context;
133:             if (queryableName != null) {
134:                 store = new KeyValueStoreWrapper<>(context, queryableName);
135:                 tupleForwarder = new TimestampedTupleForwarder<>(
136:                     store.store(),
137:                     context,
138:                     new TimestampedCacheFlushListener<>(context),
139:                     sendOldValues);
140:             }
141:         }
