17: package org.apache.kafka.streams.kstream.internals;
18: 
19: import org.apache.kafka.streams.kstream.Predicate;
20: import org.apache.kafka.streams.processor.api.ContextualProcessor;
21: import org.apache.kafka.streams.processor.api.Processor;
